external_knowledge:
- A "highly rated movie" refers to a movie with an average rating greater than 4;
- A "highly rated frame" refers to a frame with an average rating greater than 4;
- The final result is ordered by the average frame rating in descending order.

sql:
SELECT AVG(rating) AS average_rating, COUNT(*) AS total_ratings
FROM (
  SELECT rating FROM movie_ratings
  UNION ALL
  SELECT rating FROM frame_ratings
);

SELECT user_id, review
FROM frame_ratings
WHERE rating > 3;

SELECT frame_id, user_id, comment
FROM frame_comments
WHERE comment LIKE '%emotion%' OR comment LIKE '%acting%';

SELECT analysis_data, algorithm_used
FROM frame_analysis
ORDER BY created_at DESC;

